34	int TopCommand::prepare(int argc, char* const argv[]) {
35	    if (!CoreApi::IsReady()
36	            || !Android::IsSdkReady()
37	            || !(argc > 1))
38	        return Command::FINISH;
39	
40	    options.num = std::atoi(argv[1]);
41	    options.order = ORDERBY_ALLOC;
42	    options.show = false;
43	    options.obj_each_flags = 0;
44	    options.ref_each_flags = 0;
45	
46	    int opt;
47	    int option_index = 0;
48	    optind = 0; // reset
49	    static struct option long_options[] = {
50	        {"alloc",      no_argument,       0,  'a'},
51	        {"shallow",    no_argument,       0,  's'},
52	        {"native",     no_argument,       0,  'n'},
53	        {"display",    no_argument,       0,  'd'},
54	        {"app",        no_argument,       0,   1 },
55	        {"zygote",     no_argument,       0,   2 },
56	        {"image",      no_argument,       0,   3 },
57	        {"fake",       no_argument,       0,   4 },
58	        {"local",      no_argument,       0,   5 },
59	        {"global",     no_argument,       0,   6 },
60	        {"weak",       no_argument,       0,   7 },
61	        {"thread", required_argument,     0,  't'},
62	        {0,            0,                 0,   0 },
63	    };
64	
65	    while ((opt = getopt_long(argc, argv, "asndt:",
66	                long_options, &option_index)) != -1) {
67	        switch (opt) {
68	            case 'a':
69	                options.order = ORDERBY_ALLOC;
70	                break;
71	            case 's':
72	                options.order = ORDERBY_SHALLOW;
73	                break;
74	            case 'n':
75	                options.order = ORDERBY_NATIVE;
76	                break;
77	            case 'd':
78	                options.show = true;
79	                break;
80	            case 1:
81	                options.obj_each_flags |= Android::EACH_APP_OBJECTS;
82	                break;
83	            case 2:
84	                options.obj_each_flags |= Android::EACH_ZYGOTE_OBJECTS;
85	                break;
86	            case 3:
87	                options.obj_each_flags |= Android::EACH_IMAGE_OBJECTS;
88	                break;
89	            case 4:
90	                options.obj_each_flags |= Android::EACH_FAKE_OBJECTS;
91	                break;
92	            case 5:
93	                options.ref_each_flags |= Android::EACH_LOCAL_REFERENCES;
94	                break;
95	            case 6:
96	                options.ref_each_flags |= Android::EACH_GLOBAL_REFERENCES;
97	                break;
98	            case 7:
99	                options.ref_each_flags |= Android::EACH_WEAK_GLOBAL_REFERENCES;
100	                break;
101	            case 't':
102	                int tid = std::atoi(optarg);
103	                options.ref_each_flags |= (tid << Android::EACH_LOCAL_REFERENCES_BY_TID_SHIFT);
104	                break;
105	        }
106	    }
107	    options.optind = optind;
108	
109	    if (!options.obj_each_flags) {
110	        options.obj_each_flags |= Android::EACH_APP_OBJECTS;
111	        options.obj_each_flags |= Android::EACH_ZYGOTE_OBJECTS;
112	        options.obj_each_flags |= Android::EACH_IMAGE_OBJECTS;
113	        options.obj_each_flags |= Android::EACH_FAKE_OBJECTS;
114	    }
115	
116	    Android::Prepare();
117	    return Command::ONCHLD;
118	}
