120	int TopCommand::main(int argc, char* const argv[]) {
121	    std::map<art::mirror::Class, TopCommand::Pair> classes;
122	    art::mirror::Class cleaner = 0;
123	    std::vector<art::mirror::Object> cleaners;
124	    auto callback = [&](art::mirror::Object& object) -> bool {
125	        if (object.IsClass())
126	            return false;
127	
128	        art::mirror::Class thiz = object.GetClass();
129	        if (!cleaner.Ptr()) {
130	            if (thiz.PrettyDescriptor() == "sun.misc.Cleaner") {
131	                cleaner = thiz;
132	                cleaners.push_back(object);
133	            }
134	        } else if (cleaner == thiz) {
135	            cleaners.push_back(object);
136	        }
137	
138	        auto it = classes.find(thiz.Ptr());
139	        if (it == classes.end()) {
140	            TopCommand::Pair pair = {
141	                .alloc_count = 1,
142	                .shallow_size = object.SizeOf(),
143	            };
144	            classes.insert(std::pair<art::mirror::Class, TopCommand::Pair>(thiz, pair));
145	        } else {
146	            TopCommand::Pair& pair = it->second;
147	            pair.alloc_count += 1;
148	            pair.shallow_size += object.SizeOf();
149	        }
150	
151	        return false;
152	    };
153	
154	    try {
155	        if (!options.ref_each_flags) {
156	            Android::ForeachObjects(callback, options.obj_each_flags, false);
157	        } else {
158	            Android::ForeachReferences(callback, options.ref_each_flags);
159	        }
160	    } catch(InvalidAddressException& e) {
161	        LOGW("The statistical process was interrupted!\n");
162	    }
163	
164	    LOGI(ANSI_COLOR_LIGHTRED "Address       Allocations      ShallowSize        NativeSize     %s\n" ANSI_COLOR_RESET, options.show ? "ClassName" : "");
165	    art::mirror::Class cur_max_thiz = 0;
166	    TopCommand::Pair cur_max_pair = {
167	        .alloc_count = 0,
168	        .shallow_size = 0,
169	        .native_size = 0,
170	    };
171	
172	    for (int i = 0; i < cleaners.size(); i++) {
173	        sun::misc::Cleaner cleaner = cleaners[i];
174	        java::lang::Object referent = cleaner.getReferent();
175	
176	        if (referent.isNull())
177	            continue;
178	
179	        auto it = classes.find(referent.klass());
180	        if (it == classes.end())
181	            continue;
182	
183	        try {
184	            libcore::util::NativeAllocationRegistry::CleanerThunk thunk = cleaner.getThunk();
185	            if (thunk.isNull())
186	                continue;
187	
188	            libcore::util::NativeAllocationRegistry registry = thunk.getRegistry();
189	            if (registry.isNull())
190	                continue;
191	
192	            TopCommand::Pair& pair = it->second;
193	            pair.native_size += registry.getSize();
194	        } catch (InvalidAddressException& e) {}
195	    }
196	
197	    uint64_t total_count = 0;
198	    uint64_t total_shallow = 0;
199	    uint64_t total_native = 0;
200	
201	    for (const auto& value : classes) {
202	        const art::mirror::Class& thiz = value.first;
203	        const TopCommand::Pair& pair = value.second;
204	
205	        total_count += pair.alloc_count;
206	        total_shallow += pair.shallow_size;
207	        total_native += pair.native_size;
208	    }
209	
210	    LOGI("TOTAL            " ANSI_COLOR_LIGHTMAGENTA "%8" PRId64 "      " ANSI_COLOR_LIGHTBLUE "%11" PRId64 "       " ANSI_COLOR_LIGHTGREEN "%11" PRId64 "\n" ANSI_COLOR_RESET,
211	         total_count, total_shallow, total_native);
212	    LOGI("------------------------------------------------------------\n");
213	
214	    for (int i = 0; i < options.num; ++i) {
215	        for (const auto& value : classes) {
216	            const art::mirror::Class& thiz = value.first;
217	            const TopCommand::Pair& pair = value.second;
218	
219	            switch (options.order) {
220	                case ORDERBY_ALLOC: {
221	                   if (pair.alloc_count >= cur_max_pair.alloc_count) {
222	                       cur_max_thiz = thiz;
223	                       cur_max_pair = pair;
224	                   }
225	                } break;
226	                case ORDERBY_SHALLOW: {
227	                   if (pair.shallow_size >= cur_max_pair.shallow_size) {
228	                       cur_max_thiz = thiz;
229	                       cur_max_pair = pair;
230	                   }
231	                } break;
232	                case ORDERBY_NATIVE: {
233	                   if (pair.native_size >= cur_max_pair.native_size) {
234	                       cur_max_thiz = thiz;
235	                       cur_max_pair = pair;
236	                   }
237	                } break;
238	            }
239	        }
240	
241	        if (!cur_max_thiz.Ptr())
242	            break;
243	
244	        LOGI(ANSI_COLOR_LIGHTYELLOW "0x%08" PRIx64 "" ANSI_COLOR_RESET "       " "%8" PRId64 "      " "%11" PRId64 "       " "%11" PRId64 "     " ANSI_COLOR_LIGHTCYAN "%s\n" ANSI_COLOR_RESET,
245	             cur_max_thiz.Ptr(), cur_max_pair.alloc_count,
246	             cur_max_pair.shallow_size, cur_max_pair.native_size,
247	             options.show ? cur_max_thiz.PrettyDescriptor().c_str() : "");
248	
249	        classes.erase(cur_max_thiz);
250	        cur_max_thiz = 0;
251	        cur_max_pair = {0, 0, 0};
252	    }
253	    return 0;
254	}
